docSegs.md:
Fires when the pointer presses **and** releases on the same view (a true click, not a
stray press) — answered by an `onClick()` handler. The primary interaction event;
`mouseDown`/`mouseUp`/`mouseMove` are there when you need the raw phases.

code.source:
App [
    View [ width = 80, height = 44, cornerRadius = 6, fill = gainsboro, onClick() { fill = 0x4169E1 } ]
]

App [
    View [ width = 200, height = 120, fill = white, cornerRadius = 8,
      Text [ text = "hello", x = 12, y = 12 ]
    ]
]

example.source:
// View.declare — a View is a box: size + decoration + children + interaction

App [
    View [ x = 28, y = 26, width = 240, height = 150, cornerRadius = 16,
        hot: boolean = false,
        fill = { hot ? 0xE0533D : 0x2E6BE6 },
        onClick() { hot = !hot },
        Text [ x = 20, y = 20, fontSize = 15, fontWeight = semibold,
            textColor = whitesmoke, text = "click to recolor" ],
        ],
    ]

code.source:
App [ location = "home",
    why: View [ visible = { app.location == "why" } ],
]

App [ fill = white,
    header: View [ width = { app.hostWidth }, opacity = { 1 - app.scrollY / 200 } ],
]

App [
    View [ textColor = royalblue, fontSize = 14,
      Text [ text = "inherits the panel's style" ]
    ]
]

App [
    Markdown [ width = { parent.width }, text = { :body } ]
]

App [
    preview: DOMIsland [ width = { parent.width }, height = 300, slot = "run:demo" ]
]

example.source:
// TextInput.declare — the field is the source of truth; the Text reads its text live

App [ fill = white, textColor = black,
    View [ x = 28, y = 30,
        layout: SimpleLayout [ axis = y, spacing = 16 ],
        field: TextInput [ width = 300, height = 34, padding = 8, cornerRadius = 8,
            fill = gainsboro, placeholder = "type here" ],
        Text [ fontSize = 22, fontWeight = semibold,
            text = { "hello, " + (parent.field.text || "world") } ],
        ],
    ]

code.source:
App [
    View [ layout: SimpleLayout [ axis = y, spacing = 10 ],
        Text [ text = "one" ],
        Text [ text = "two" ],
    ]
]

example.source:
// SimpleLayout.declare — children stacked down the y axis, evenly spaced

App [ fill = white, textColor = black,
    View [ x = 28, y = 24,
        layout: SimpleLayout [ axis = y, spacing = 12 ],
        Bar [ width = 320, label = "north", value = 72, tint = royalblue ],
        Bar [ width = 320, label = "east",  value = 54, tint = dodgerblue ],
        Bar [ width = 320, label = "south", value = 88, tint = cornflowerblue ],
        Bar [ width = 320, label = "west",  value = 41, tint = lightskyblue ],
        ],
    ]

code.source:
App [
    View [ width = { parent.width }, layout: WrappingLayout [ spacing = 8, lineSpacing = 8 ] ]
]

example.source:
// Animator.declare — click the box; the Animator drives its x to the target

App [
    View [ x = 28, y = 88, width = 80, height = 80, cornerRadius = 12, fill = dodgerblue,
        onClick() { slide.start() },
        Text [ x = 18, y = 30, fontSize = 15, fontWeight = semibold,
            textColor = whitesmoke, text = "click" ],
        slide: Animator [ attribute = x, to = 460, duration = 500, motion = easeOut ],
        ],
    ]

